1	// src/model-router.ts — Thin shim over @mariozechner/pi-ai.
2	//
3	// Evening 1 of the pi-ai migration: we keep the exported chatCompletion()
4	// signature identical to before so agent.ts, onboard.ts, and heartbeat.ts
5	// don't need to change yet. All provider-specific quirks (Qwen tool-call
6	// formatting, Google multimodal image fetching, OpenRouter HTML error walls)
7	// are handled inside pi-ai now. This file just translates between our
8	// Anthropic-flavored ChatMessage/ModelResponse types and pi-ai's Context /
9	// AssistantMessage types.
10	//
11	// Evening 2 will delete most of this translation code when the agent loop
12	// moves to pi-agent-core's Agent class and callers start consuming pi-ai
13	// shapes directly.
14	
15	import type Anthropic from "@anthropic-ai/sdk";
16	import {
17	  completeSimple,
18	  getModel,
19	  Type,
20	  type AssistantMessage,
21	  type Context,
22	  type ImageContent,
23	  type KnownProvider,
24	  type Message,
25	  type TextContent,
26	  type Tool,
27	  type ToolResultMessage,
28	} from "@mariozechner/pi-ai";
29	
30	// ---------------------------------------------------------------------------
31	// Public types — unchanged from the pre-migration surface so callers are
32	// untouched in Evening 1.
33	// ---------------------------------------------------------------------------
34	
35	export type ModelBackend = "anthropic" | "openrouter" | "google";
36	
37	export interface ModelRoute {
38	  backend: ModelBackend;
39	  modelId: string;
40	}
41	
42	export interface ChatMessage {
43	  role: "user" | "assistant";
44	  content: string | Anthropic.ContentBlock[];
45	}
46	
47	export interface ToolDefinition {
48	  name: string;
49	  description: string;
50	  input_schema: Record<string, unknown>;
51	}
52	
53	export interface ModelResponse {
54	  content: Anthropic.ContentBlock[];
55	  stop_reason: string | null;
56	}
57	
58	// ---------------------------------------------------------------------------
59	// Model string parsing — same prefix scheme the config files already use:
60	//   "openrouter/qwen/qwen3.5-plus-02-15"
61	//   "google/gemini-2.5-pro"
62	//   "claude-haiku-4-5"                    (no prefix → anthropic)
63	// ---------------------------------------------------------------------------
64	
65	export function parseModelString(model: string): ModelRoute {
66	  if (model.startsWith("google/")) {
67	    return { backend: "google", modelId: model.slice("google/".length) };
68	  }
69	  if (model.startsWith("openrouter/")) {
70	    return { backend: "openrouter", modelId: model.slice("openrouter/".length) };
71	  }
72	  return { backend: "anthropic", modelId: model };
73	}
74	
75	function backendToProvider(backend: ModelBackend): KnownProvider {
76	  // Our backend names happen to match pi-ai's provider names one-to-one.
77	  return backend;
78	}
79	
80	// ---------------------------------------------------------------------------
81	// Message translation: our ChatMessage[] → pi-ai Message[].
82	//
83	// The trick is assistant messages with tool_use blocks: pi-ai's AssistantMessage
84	// carries many metadata fields (api, provider, model, usage, stopReason, ...)
85	// that we don't have when replaying history mid-loop. We synthesize sensible
86	// placeholders. pi-ai uses these for its own bookkeeping, not as part of the
87	// wire format sent to providers, so placeholder values are fine.
88	// ---------------------------------------------------------------------------
89	
90	async function fetchImageAsContent(url: string): Promise<ImageContent | TextContent> {
91	  try {
92	    const res = await fetch(url);
93	    const buffer = Buffer.from(await res.arrayBuffer());
94	    const mimeType = res.headers.get("content-type") || "image/png";
95	    return { type: "image", data: buffer.toString("base64"), mimeType };
96	  } catch {
97	    return { type: "text", text: `[Image failed to load: ${url}]` };
98	  }
99	}
